import urllib.request

def get_percentile(nums, target):
    nums.sort()
    rank = sum(1 for n in nums if n < target) + 1
    return rank / len(nums) * 100

def get_percentile_text(nums, target):
    return f"42 is in the {get_percentile(nums, 42):.1f}th percentile"

def get_sorted(nums):
    return sorted(nums, reverse=True)

def get_percentile_summary(nums, target):
    return f"Sorted: {get_sorted(nums)}, 42 is in the {get_percentile(nums, target):.1f}th percentile"

